import{_ as t,o,c as a,au as i}from"./chunks/framework.Bpqx6pAq.js";const h=JSON.parse('{"title":"Capture utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/utilities/utils.capture.md","filePath":"api/map/utilities/utils.capture.md"}'),r={name:"api/map/utilities/utils.capture.md"};function c(s,e,l,d,n,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="capture-utilities" tabindex="-1">Capture utilities <a class="header-anchor" href="#capture-utilities" aria-label="Permalink to &quot;Capture utilities&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This module provides the <code>capture</code> function for generating map screenshots or PDF exports via the KDK capture service. It supports single or multi-time captures and assembles the results into image files or a multi-page PDF.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="capture-values" tabindex="-1"><code>capture(values)</code> <a class="header-anchor" href="#capture-values" aria-label="Permalink to &quot;`capture(values)`&quot;">​</a></h3><p>Sends a capture request to the KDK capture service for the current map activity and exports the result as image(s) or a PDF.</p><ul><li><strong>Parameters:</strong><ul><li><code>values</code> <em>(Object)</em>: Capture configuration object: <ul><li><code>dateTime.start</code> <em>(string)</em>: ISO 8601 start datetime for the capture range.</li><li><code>dateTime.end</code> <em>(string)</em>: ISO 8601 end datetime for the capture range. When equal to <code>start</code>, a single capture is produced.</li><li><code>resolution.width</code> <em>(string | number)</em>: Width of the output image in pixels.</li><li><code>resolution.height</code> <em>(string | number)</em>: Height of the output image in pixels.</li><li><code>format</code> <em>(&#39;pdf&#39; | string)</em>: Output format. When <code>&#39;pdf&#39;</code>, all captures are assembled into a single PDF; otherwise each capture is exported as a separate PNG file.</li><li><code>header</code> <em>(string, optional)</em>: Text content for the capture header overlay.</li><li><code>footer</code> <em>(string, optional)</em>: Text content for the capture footer overlay.</li><li><code>north</code> <em>(string, optional)</em>: Placement for the north arrow sticky (e.g. <code>&#39;top-right&#39;</code>). Must be one of: <code>right</code>, <code>left</code>, <code>top</code>, <code>bottom</code>, <code>top-left</code>, <code>top-right</code>, <code>bottom-right</code>, <code>bottom-left</code>.</li><li><code>legend</code> <em>(string, optional)</em>: Placement for the legend window (same placement values as <code>north</code>).</li><li><code>basePath</code> <em>(string, optional)</em>: Base URL path passed to the capture service. Defaults to <code>&#39;/#/home/&#39;</code>.</li></ul></li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code> — Triggers a file download for each captured image or the assembled PDF.</li></ul><h4 id="behaviour" tabindex="-1">Behaviour <a class="header-anchor" href="#behaviour" aria-label="Permalink to &quot;Behaviour&quot;">​</a></h4><ol><li>Reads the current activity&#39;s layer state and view bounding box.</li><li>Generates a date array between <code>start</code> and <code>end</code> using the current timeline step from the global store (<code>time.interval</code>).</li><li>Posts each capture request to the gateway&#39;s <code>/capture</code> endpoint with a <code>Bearer</code> JWT if configured.</li><li>Shows a Quasar notification spinner during the operation.</li><li>On success, exports the result(s) using Quasar&#39;s <code>exportFile</code>.</li><li>On network/service error, emits a global <code>error</code> event.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>File names are resolved using i18n keys <code>utils.capture.CAPTURE_PDF_FILE</code> and <code>utils.capture.CAPTURE_IMAGE_FILE</code>, which receive the capture time as a template variable.</p></div>',10)])])}const m=t(r,[["render",c]]);export{h as __pageData,m as default};
